window.BLOG_I18N = {"he":{"dateLocale":"he-IL","ui":{"pageTitle":"הבלוג של Hunch — התאמה ארכיטקטונית לקוד AI","pageDescription":"הערות, מדדים וטיעונים על שמירת קוד שנוצר ב-AI בתוך הארכיטקטורה שלכם.","mainNav":"ניווט ראשי","language":"שפה","navHow":"כך זה עובד","navInside":"מאחורי הקלעים","docs":"תיעוד","blog":"בלוג","changelog":"יומן שינויים","getStarted":"מתחילים","eyebrow":"הבלוג של Hunch","mastheadTitle":"שומרים את ה-AI בתוך הארכיטקטורה שלכם.","mastheadIntro":"מדדים, טיעונים והערות מהשטח על הטעויות שה-linter לא רואה — ועל שער דטרמיניסטי שכן תופס אותן.","pinned":"מומלץ","allPosts":"כל המאמרים","pinnedLabel":"★ מומלץ","readRelease":"לקריאת המאמר","read":"לקריאה","blogName":"הבלוג של Hunch","notFound":"המאמר לא נמצא","notFoundBody":"המאמר הזה אינו קיים.","backToBlog":"חזרה לבלוג","older":"מאמר קודם ←","newer":"→ מאמר חדש יותר","ctaTitle":"שמרו על הארכיטקטורה בכל שינוי של AI.","ctaBody":"אילוץ אחד, שער אחד, בלי מודל שמחליט.","keyIdeas":"הרעיונות המרכזיים","takeawayHeading":"מה לוקחים מכאן","footerTag":"© Hunch — התאמה ארכיטקטונית לקוד AI.","allPostsFooter":"כל המאמרים"},"posts":[{"slug":"one-memory-for-the-whole-team","title":"Hunch 1.9: זיכרון חי אחד לכל הצוות","dek":"מצב Matrix מעביר את הזיכרון ההנדסי למאגר Git פרטי ייעודי בשליטת הצוות, ושומר כל clone, worktree, בדיקת CLI ועוזר מחובר על אותו גרף חי.","tag":"גרסה","read":"5 דקות","points":["מתחזק מחבר פעם אחת מאגר זיכרון פרטי; מאגר הקוד שומר רק מצביע ללא פרטי גישה.","פעולות CLI וכלי MCP מרעננים את הגרף, ולכידות מסתנכרנות אוטומטית עם מיזוג דטרמיניסטי.","הזיכרון נשאר פרטי וסמכות חסימה עדיין דורשת פעולה אנושית מפורשת."],"takeaway":"Matrix נותן לכל הצוות היסטוריה הנדסית אחת בלי להעביר אחסון או סמכות ל-Hunch."},{"slug":"python-joins-the-graph","title":"Hunch 1.8.1: הגרף לומד Python","dek":"AI הפך את Python לשפה הפופולרית ביותר ב-GitHub — ובקוד Python שנכתב ב-AI סטייה ארכיטקטונית יכולה להסתתר בלי קומפיילר שישגיח. גרסה 1.8.1 מוסיפה סמלים, קריאות, imports וטווח השפעה ל-Python.","tag":"גרסה","read":"7 דקות","points":["המנתח החדש מחבר פונקציות, מחלקות, imports וקריאות לאותו גרף שכבר משמש לבדיקות התאמה.","מרשם שפות מפריד בין מנוע הגרף לבין התחביר, ולכן הוספת השפה הבאה דורשת רכיב ממוקד במקום שכתוב.","הגרסה נולדה מבקשת הקהילה ונבדקה על מאגרי Python אמיתיים, כולל ניתוח טווח ההשפעה."],"takeaway":"זיכרון הנדסי שימושי רק אם הוא מגיע לקוד שבו הצוות עובד. כעת אותם כללים והסברים חלים גם על בסיסי קוד ב-Python."},{"slug":"change-gate-private-workflows","title":"Hunch 1.5: לכל שינוי קוד יש זיכרון — לפני שהוא נשלח","dek":"Change Gate החדש מביא את אותה בדיקת קדם-טיסה דטרמיניסטית ל-CLI, ל-MCP ול-VS Code. שכבות פרטיות משאירות הסברים רגישים מקומיים.","tag":"גרסה","read":"7 דקות","points":["אותה בדיקת התאמה פועלת לפני משלוח שינוי, בלי קשר לסוכן או לעורך שכתב אותו.","הכללים וההחלטות מגיעים עם ראיות, כך שחסימה מסבירה איזו בחירה נשמרת ואיזה באג היא מונעת.","Private overlays מאפשרים לשמור הקשר רגיש מחוץ למאגר הציבורי ועדיין להשתמש בו בעבודה המקומית."],"takeaway":"הערך אינו עוד אזהרה אחרי ה-PR, אלא שער אחד ועקבי שמופעל בדיוק לפני שהשינוי יוצא מהידיים שלכם."},{"slug":"skills-are-never-read","title":"התקנו skill לסוכן ב-20 סשנים. הוא נקרא אפס פעמים.","dek":"מדד על באגים אמיתיים ב-zod הראה ש-skill קפדני לא השפיע כלל, מפני שאף מודל לא פתח אותו. מסירה כפויה הפכה באגים קשים מכישלון להצלחה.","tag":"מדד","read":"9 דקות","points":["קובץ הנחיות שנמצא במאגר אינו מבטיח שהסוכן יראה אותו ברגע שבו הוא חשוב.","ב-20 סשנים המודלים לא קראו את ה-skill אפילו פעם אחת; לכן התוצאה נשארה זהה לתרחיש בלי ההנחיה.","העברת ההנחיה דרך hook שאי אפשר לפספס שינתה את התוצאות, ושער ההתאמה תפס גם טעות של מחבר הכלי עצמו."],"takeaway":"אל תמדדו את איכות ההנחיות בלבד. מדדו אם הן באמת נמסרו, ואם בדיקה דטרמיניסטית תופסת את המקרים שבהם המודל עדיין מתעלם מהן."},{"slug":"agent-audits-its-own-memory","title":"נתנו ל-AI לבדוק את כלי הזיכרון שלו. הוא השתמש ב-4 מתוך 19 כלים.","dek":"אחרי שבועיים של עבודה אמיתית בתוך Hunch ביקשנו מהסוכן לבדוק היכן חזר ל-grep ולמה. הממצאים הפכו לגרסה 1.3.0 ושיפרו Recall@10 מ-90% ל-100%.","tag":"שימוש עצמי","read":"6 דקות","points":["רשימת כלים ארוכה אינה שווה לשימוש טוב: הסוכן בחר שוב ושוב בכמה מסלולים מוכרים והתעלם מהשאר.","הביקורת השוותה בין כוונת הכלים לבין התנהגות בפועל, כולל המקומות שבהם grep היה קל יותר מהזיכרון המובנה.","השינויים הוכחו מול golden set שמור, ושימוש חוזר בהקשר קיצץ את עלות האיסוף בערך פי מאה."],"takeaway":"כלי סוכן צריך להיבחן מתוך ההתנהגות האמיתית של הסוכן, לא מתוך רשימת היכולות שלו. עקבו אחרי נתיבי השימוש ושפרו את המסלול הקצר ביותר לתשובה."},{"slug":"ai-ignores-your-architecture","title":"AI מתעלם מכללי הארכיטקטורה שלכם — גם בחזית. מדדנו את זה.","dek":"AI יכול לשכתב controller כך שייגש ישירות למסד הנתונים, בזמן ש-Semgrep, SonarQube ו-ESLint נשארים ירוקים. בדקנו אם עצם הצגת הכלל למודל עוצרת זאת.","tag":"מדד","read":"8 דקות","points":["הכשל אינו בהכרח pattern אסור בשורה אחת; הוא תכונה של המסלול בגרף הקריאות.","גם כשכלל הארכיטקטורה מופיע במפורש בהקשר, המודל יכול להעדיף שינוי מקומי שנראה נקי ונכון.","בדיקות תחביר וסריקות pattern עברו, בעוד שבדיקה דטרמיניסטית של הנתיב controller→database זיהתה את ההפרה."],"takeaway":"הנחיה למודל מועילה, אך אינה שער. כללים קריטיים צריכים ייצוג שאפשר לבדוק על הגרף אחרי שהקוד נכתב."},{"slug":"agents-md-is-lying-to-your-agent","title":"קובץ AGENTS.md משקר לסוכן שלכם — ושום דבר לא בודק אותו","dek":"האקוסיסטם אימץ זיכרון ב-Markdown: AGENTS.md, CLAUDE.md וקובצי rules. הם נשמרים ב-Git וניתנים לסקירה — אבל מתיישנים בשקט ובאותה סמכות.","tag":"גרסה","read":"5 דקות","points":["הוראה ישנה יכולה להמשיך להישלח לסוכן גם אחרי שהקוד והארכיטקטורה השתנו.","הבעיה מסוכנת במיוחד משום שהקובץ נראה רשמי, ולכן הסוכן מתייחס למידע מיושן כאמת פעילה.","Hunch 1.1 מתייחס לקובצי ההנחיות כמשטח drift ומשווה אותם למבנה ולהחלטות הנוכחיים."],"takeaway":"זיכרון כתוב צריך מחזור חיים: מקור, תאריך, בעלות ובדיקת התאמה. בלי זה, תיעוד טוב הופך בהדרגה להנחיה מזיקה."},{"slug":"the-violation-your-linter-cant-see","title":"ההפרה שה-linter שלכם לא רואה","dek":"Semgrep, SonarQube ו-ESLint מתאימים תבניות. טעויות ה-AI היקרות ביותר הן לעיתים תכונות של גרף הקריאות, לא תבניות טקסט.","tag":"לעומק","read":"6 דקות","points":["כלי pattern מצטיינים באיתור API אסור או מבנה תחבירי מוכר, אבל לא בהוכחת מסלול דרך כמה פונקציות.","כלל כמו ‘controllers לא מגיעים למסד הנתונים’ דורש להבין סמלים, קריאות ותלויות מעבר לגבולות קבצים.","גרף דטרמיניסטי מאפשר לבדוק must-reach, must-not-reach וכיוון תלויות בלי לשאול מודל לדעתו."],"takeaway":"השתמשו ב-linter למה שהוא יודע לעשות, והוסיפו בדיקת גרף לכללים שמדברים על מסלולים, שכבות וגבולות ארכיטקטוניים."},{"slug":"just-put-it-in-the-prompt","title":"„פשוט שימו את זה ב-prompt” לא מחזיק","dek":"כל הרעיון של זיכרון AI הוא שהקשר משנה התנהגות. זה נכון — אבל במדד שלנו גם מודל חזית התעלם מכלל ארכיטקטוני מפורש ב-60% מהמקרים.","tag":"טיעון","read":"5 דקות","points":["הקשר טוב מגדיל את הסיכוי לבחירה נכונה ומסביר למודל למה כלל קיים.","הוא אינו הופך מודל הסתברותי למערכת אכיפה; ניסוח ברור עדיין יכול להידחק הצדה מול מטרה מקומית.","המדד הפריד בין מסירה, ציות ואכיפה והראה שלכל שכבה תפקיד אחר."],"takeaway":"שימו את הסיבה ב-prompt כדי למנוע טעויות, ואז בדקו את התוצאה באופן דטרמיניסטי כדי לתפוס את מה שלא נמנע."},{"slug":"architectural-conformance-explained","title":"התאמה ארכיטקטונית, בפשטות","dek":"כך משפט כמו „controllers אינם נוגעים במסד הנתונים” הופך לבדיקה דטרמיניסטית על גרף התלויות — בלי מודל בתהליך ההכרעה.","tag":"כך זה עובד","read":"6 דקות","points":["תחילה מתרגמים כוונה אנושית להיקף מדויק: נקודת מוצא, יעד אסור והחרגות מפורשות.","לאחר מכן הגרף עוקב אחרי מסלולי הקריאה בפועל, גם כשהחיבור עובר דרך כמה קבצים או wrappers.","התוצאה כוללת receipt: המסלול המפר, ההחלטה שמאחורי הכלל והבאג שהוא נועד למנוע."],"takeaway":"כלל טוב הוא ספציפי, ניתן להפרכה וקשור לראיות. כך אפשר לאכוף ארכיטקטורה בלי להפוך את המודל לשופט של עצמו."},{"slug":"memory-that-travels-with-your-code","title":"זיכרון שנוסע עם הקוד שלכם","dek":"זיכרונות של עוזרים עשויים להיות בצד השרת, לפוג או להישאר במחשב אחד. החלופה: אילוצים והחלטות כ-JSON שמור ב-Git ועובד עם כל עוזר.","tag":"ארכיטקטורה","read":"5 דקות","points":["זיכרון שמחובר לספק או למכשיר נעלם בדיוק כשצוות, כלי או סביבת עבודה מתחלפים.","רשומות פשוטות ב-Git ניתנות לסקירה, לגרסאות ולמיזוג לצד הקוד שעליו הן מסבירות.","פרוטוקול MCP וחיבורים לעורכים מאפשרים לכמה עוזרים לקרוא מאותו מקור אמת."],"takeaway":"שמרו את הידע במיקום שהצוות כבר יודע לנהל: ליד הקוד, בפורמט פתוח, עם היסטוריה ובלי תלות בעוזר מסוים."},{"slug":"never-twice","title":"לא פעמיים: תיקון שהופך לכלל נאכף","dek":"אמרתם ל-AI „לא, לעולם אל תייבא lodash כאן” — ובסשן הבא הוא שכח. הפתרון הוא להפוך את התיקון לאילוץ מדויק ונייד.","tag":"לכידה","read":"5 דקות","points":["תיקון אנושי הוא אות חזק: מישהו כבר שילם את עלות ההבנה והגדיר מה לא צריך לקרות שוב.","במקום להשאיר את התיקון בשיחה חולפת, Hunch לוכד היקף, סיבה ודוגמה נגדית ככלל שניתן לבדיקה.","הכלל נשמר ב-Git ומופעל באותה צורה בכל עוזר ובכל סשן עתידי."],"takeaway":"כשתיקון חשוב חוזר, אל תנסחו אותו מחדש. הפכו אותו פעם אחת לזיכרון עם היקף ובדיקה, ואז תנו למערכת לזכור."},{"slug":"the-receipt","title":"הקבלה: אכיפה שמסבירה את עצמה","dek":"linter חוסם עם מזהה כלל. שער טוב חוסם עם ההחלטה שמאחורי הכלל והבאג שהוא מונע לפתוח מחדש.","tag":"אכיפה","read":"4 דקות","points":["חסימה ללא הקשר נראית שרירותית ומזמינה עקיפה או מחיקה של הכלל.","receipt מחבר את ההפרה למסלול הקוד, להחלטה המקורית ולראיה ההיסטורית שתומכת בה.","כאשר המפתח יכול לבדוק את הסיבה, אפשר להבחין בין רגרסיה אמיתית לבין כלל שכבר אינו נכון."],"takeaway":"אמון באכיפה מגיע משקיפות. הציגו לא רק מה נכשל, אלא למה הכלל קיים ומה צריך להשתנות כדי לעבור בבטחה."},{"slug":"prevent-and-catch","title":"למנוע ולתפוס: למה צריך את שתי השכבות","dek":"הזרקת הקשר מונעת את ההפרות שהמודל מוכן לציית להן. השער הדטרמיניסטי תופס את השאר. המדד שלנו מראה למה אף שכבה אינה מספיקה לבדה.","tag":"אסטרטגיה","read":"5 דקות","points":["מניעה מוקדמת חוסכת עבודה: הסוכן רואה את הסיבה לפני העריכה ויכול לבחור מסלול נכון מלכתחילה.","אבל מודל עדיין עלול להתעלם, לפרש לא נכון או לאבד את ההנחיה בתוך הקשר ארוך.","בדיקה אחרי השינוי מספקת רשת ביטחון אובייקטיבית ומחזירה receipt שימושי לתיקון."],"takeaway":"השתמשו בזיכרון כדי לכוון ובשער כדי להבטיח. שתי השכבות חולקות את אותו כלל, אך פועלות ברגעים שונים."},{"slug":"ai-code-review-is-not-enough","title":"סקירת קוד ב-AI נחוצה. היא לא השער.","dek":"CodeRabbit, Greptile ו-Qodo הופכים PR-ים שנוצרו ב-AI לניתנים לסקירה בקנה מידה. אבל סוקר AI הוא מגיב הסתברותי, וסטייה ארכיטקטונית דורשת בדיקה דטרמיניסטית.","tag":"השוואה","read":"5 דקות","points":["סקירת AI טובה בהסבר, איתור ריחות והפניית תשומת לב אנושית לאזורים מסוכנים.","אותו שינוי יכול לקבל הערות שונות בין ריצות, ולכן הערה אינה חוזה אכיפה אמין.","כללי גרף דטרמיניסטיים משלימים את הסקירה: הם נותנים תשובת pass/fail יציבה לגבולות קריטיים."],"takeaway":"השאירו את השיפוט העשיר לסקירה, ואת האילוצים שאסור להפר לשער שניתן להריץ שוב ולקבל אותה תשובה."},{"slug":"conformance-in-ci-in-5-minutes","title":"התאמה ארכיטקטונית ב-CI בתוך 5 דקות","dek":"רושמים אילוץ אחד, מחברים שער אחד ורואים אותו חוסם שינוי AI ששובר את הארכיטקטורה — ומעביר כל מה שלא.","tag":"מדריך","read":"4 דקות","points":["התחילו בכלל צר ובעל ערך, למשל איסור על controllers להגיע ישירות לשכבת מסד הנתונים.","הריצו את Hunch מקומית כדי לבדוק את ההיקף ואת ה-receipt לפני שמוסיפים אותו ל-CI.","הוסיפו את פקודת ההתאמה ל-workflow כך שכל PR נבדק מול אותו גרף ואותו מקור אמת."],"takeaway":"הצלחה ראשונה צריכה להיות קטנה ומדידה: הפרה מכוונת אחת נכשלת, שינוי תקין עובר, והצוות מבין את ההסבר."}]},"ru":{"dateLocale":"ru-RU","ui":{"pageTitle":"Блог Hunch — архитектурное соответствие для ИИ-кода","pageDescription":"Заметки, тесты и аргументы о том, как удерживать созданный ИИ код внутри вашей архитектуры.","mainNav":"Основная навигация","language":"Язык","navHow":"Как это работает","navInside":"Что внутри","docs":"Документация","blog":"Блог","changelog":"История изменений","getStarted":"Начать","eyebrow":"Блог Hunch","mastheadTitle":"Удерживаем ИИ внутри вашей архитектуры.","mastheadIntro":"Тесты, аргументы и полевые заметки об ошибках, которых не видит линтер, — и о детерминированном барьере, который их ловит.","pinned":"Главное","allPosts":"Все статьи","pinnedLabel":"★ Главное","readRelease":"Читать статью","read":"Читать","blogName":"Блог Hunch","notFound":"Статья не найдена","notFoundBody":"Такой статьи не существует.","backToBlog":"Вернуться в блог","older":"← Раньше","newer":"Новее →","ctaTitle":"Защищайте архитектуру при каждом изменении ИИ.","ctaBody":"Одно ограничение, один барьер, без модели в роли судьи.","keyIdeas":"Главные идеи","takeawayHeading":"Практический вывод","footerTag":"© Hunch — архитектурное соответствие для ИИ-кода.","allPostsFooter":"Все статьи"},"posts":[{"slug":"one-memory-for-the-whole-team","title":"Hunch 1.9: единая живая память для всей команды","dek":"Matrix переносит инженерную память в выделенный приватный Git-репозиторий под контролем команды и держит каждый клон, worktree, CLI-проверку и подключённого помощника на одном живом графе.","tag":"Релиз","read":"5 мин","points":["Сопровождающий один раз подключает приватный репозиторий памяти; кодовый репозиторий хранит только указатель без учётных данных.","CLI и MCP обновляют граф, а записи синхронизируются автоматически и объединяются детерминированно.","Память остаётся приватной, а блокирующие полномочия всё ещё требуют явного действия человека."],"takeaway":"Matrix даёт всей команде одну инженерную историю, не передавая Hunch хранение данных или полномочия."},{"slug":"python-joins-the-graph","title":"Hunch 1.8.1: граф изучает Python","dek":"ИИ сделал Python самым популярным языком на GitHub, а архитектурный дрейф в написанном ИИ Python-коде легко скрывается без контроля компилятора. v1.8.1 добавляет символы, вызовы, импорты и радиус влияния.","tag":"Релиз","read":"7 мин","points":["Новый анализатор связывает функции, классы, импорты и вызовы в тот же граф, который используется для проверок соответствия.","Реестр языков отделяет движок графа от синтаксиса, поэтому следующий язык добавляется отдельным адаптером, а не переписыванием системы.","Релиз вырос из запроса сообщества и проверялся на реальных Python-репозиториях, включая анализ радиуса влияния."],"takeaway":"Инженерная память полезна только там, где живёт код команды. Теперь те же правила и объяснения работают и для Python-кодовых баз."},{"slug":"change-gate-private-workflows","title":"Hunch 1.5: память для каждого изменения — до отправки","dek":"Новый Change Gate переносит одну и ту же детерминированную предполётную проверку в CLI, MCP и VS Code. Приватные слои оставляют чувствительные объяснения локально.","tag":"Релиз","read":"7 мин","points":["Одна проверка соответствия запускается перед отправкой изменения независимо от агента или редактора.","Правила сопровождаются доказательствами: блокировка показывает решение, которое защищает, и ошибку, которую не даёт вернуть.","Private overlays позволяют держать конфиденциальный контекст вне публичного репозитория и использовать его локально."],"takeaway":"Ценность не в ещё одном комментарии после PR, а в едином барьере непосредственно перед тем, как изменение покинет рабочую среду."},{"slug":"skills-are-never-read","title":"Мы установили навык агента в 20 сессиях. Его не прочитали ни разу.","dek":"Тест на реальных ошибках zod показал, что тщательно написанный навык ничего не менял: модели его не открывали. Принудительная доставка превратила сложные FAIL в PASS.","tag":"Бенчмарк","read":"9 мин","points":["Файл инструкций в репозитории не гарантирует, что агент увидит его в нужный момент.","За 20 сессий модели ни разу не прочитали навык, поэтому результат не отличался от сценария без инструкции.","Доставка через обязательный hook изменила результат, а барьер соответствия затем поймал ошибку даже у автора инструмента."],"takeaway":"Оценивайте не только качество инструкций, но и факт их доставки. А затем детерминированно проверяйте случаи, когда модель всё равно не подчинилась."},{"slug":"agent-audits-its-own-memory","title":"Мы дали ИИ проверить собственную память. Он использовал 4 инструмента из 19.","dek":"После двух недель реальной работы внутри Hunch агент проверил, где возвращался к grep и почему. Выводы вошли в v1.3.0 и подняли Recall@10 с 90% до 100%.","tag":"Догфудинг","read":"6 мин","points":["Длинный список возможностей не равен хорошему использованию: агент выбирал несколько знакомых маршрутов и игнорировал остальные.","Аудит сравнил назначение инструментов с реальным поведением, особенно там, где grep казался проще встроенной памяти.","Изменения подтвердили на зафиксированном golden set, а повторное использование контекста снизило стоимость сбора примерно в сто раз."],"takeaway":"Инструмент для агента надо оценивать по поведению агента, а не по каталогу функций. Измеряйте реальные пути и сокращайте маршрут к правильному ответу."},{"slug":"ai-ignores-your-architecture","title":"ИИ игнорирует правила архитектуры — даже передовые модели. Мы измерили.","dek":"ИИ может переписать контроллер так, чтобы он обращался к базе напрямую, пока Semgrep, SonarQube и ESLint остаются зелёными. Мы проверили, помогает ли простое предъявление правила.","tag":"Бенчмарк","read":"8 мин","points":["Нарушение часто не является запрещённым паттерном в одной строке: это свойство пути в графе вызовов.","Даже явное правило в контексте не мешает модели выбрать локально аккуратное, но архитектурно неверное изменение.","Синтаксические проверки прошли, а детерминированная проверка пути controller→database обнаружила нарушение."],"takeaway":"Инструкция полезна, но не является барьером. Критические правила нужно представлять так, чтобы граф мог проверить результат после генерации кода."},{"slug":"agents-md-is-lying-to-your-agent","title":"Ваш AGENTS.md лжёт агенту — и никто это не проверяет","dek":"Экосистема стандартизировала память в Markdown: AGENTS.md, CLAUDE.md и rules-файлы. Они хранятся в Git и доступны для ревью, но незаметно устаревают, сохраняя авторитет.","tag":"Релиз","read":"5 мин","points":["Старая инструкция продолжает приходить агенту даже после изменения кода и архитектуры.","Файл выглядит официальным, поэтому устаревшая информация воспринимается как действующее правило.","Hunch 1.1 считает файлы инструкций поверхностью дрейфа и сверяет их с текущей структурой и решениями."],"takeaway":"Письменной памяти нужен жизненный цикл: источник, дата, владелец и проверка соответствия. Иначе хорошая документация постепенно становится вредной инструкцией."},{"slug":"the-violation-your-linter-cant-see","title":"Нарушение, которого не видит ваш линтер","dek":"Semgrep, SonarQube и ESLint сопоставляют паттерны. Самые дорогие ошибки ИИ часто являются свойствами графа вызовов, а не текстовыми шаблонами.","tag":"Разбор","read":"6 мин","points":["Паттерн-инструменты отлично находят запрещённый API или известную конструкцию, но не доказывают путь через несколько функций.","Правило «контроллеры не достигают базы» требует понимать символы, вызовы и зависимости между файлами.","Детерминированный граф проверяет must-reach, must-not-reach и направление зависимостей без мнения модели."],"takeaway":"Оставьте линтеру паттерны, а для правил о путях, слоях и границах добавьте проверку графа."},{"slug":"just-put-it-in-the-prompt","title":"«Просто добавьте это в промпт» не работает","dek":"Контекст действительно меняет поведение. Но в нашем тесте даже передовая модель игнорировала явное архитектурное правило в 60% случаев. Это необходимо, но недостаточно.","tag":"Аргумент","read":"5 мин","points":["Хороший контекст повышает шанс верного выбора и объясняет, почему правило существует.","Он не превращает вероятностную модель в систему исполнения: ясная инструкция всё ещё может уступить локальной цели.","Тест разделил доставку, соблюдение и контроль и показал, что это три разные задачи."],"takeaway":"Передавайте причину в промпте для предотвращения ошибок, а затем детерминированно проверяйте результат, чтобы поймать оставшиеся."},{"slug":"architectural-conformance-explained","title":"Архитектурное соответствие: простое объяснение","dek":"Как фраза «контроллеры не должны касаться БД» превращается в детерминированную проверку графа зависимостей без модели в контуре решения.","tag":"Как устроено","read":"6 мин","points":["Человеческое намерение переводится в точную область: стартовые символы, запрещённую цель и явные исключения.","Граф отслеживает реальные пути вызовов, даже когда связь проходит через несколько файлов и обёрток.","Результат содержит receipt: нарушающий путь, решение за правилом и ошибку, возврат которой оно предотвращает."],"takeaway":"Хорошее правило конкретно, опровержимо и связано с доказательством. Так архитектуру можно контролировать, не делая модель судьёй самой себя."},{"slug":"memory-that-travels-with-your-code","title":"Память, которая путешествует вместе с кодом","dek":"Память помощника может храниться на сервере, истекать или оставаться на одном компьютере. Альтернатива — ограничения и решения в JSON под Git, доступные любому агенту.","tag":"Архитектура","read":"5 мин","points":["Память, привязанная к поставщику или устройству, пропадает при смене команды, инструмента или рабочей среды.","Простые записи в Git можно ревьюить, версионировать и объединять рядом с кодом, который они объясняют.","MCP и интеграции редакторов дают разным помощникам общий источник истины."],"takeaway":"Храните знания там, где команда уже умеет ими управлять: рядом с кодом, в открытом формате, с историей и без привязки к одному агенту."},{"slug":"never-twice","title":"Никогда дважды: исправление становится исполняемым правилом","dek":"Вы сказали ИИ «никогда не импортируй lodash здесь», а следующая сессия всё забыла. Решение — превратить исправление в точное переносимое ограничение.","tag":"Фиксация","read":"5 мин","points":["Человеческая коррекция — сильный сигнал: кто-то уже заплатил за понимание и определил, что не должно повториться.","Hunch сохраняет область, причину и контрпример как проверяемое правило вместо исчезающей реплики в чате.","Правило живёт в Git и одинаково действует для любого помощника и будущей сессии."],"takeaway":"Не формулируйте важную коррекцию заново. Один раз превратите её в память с областью и проверкой — и позвольте системе помнить."},{"slug":"the-receipt","title":"Квитанция: контроль, который объясняет себя","dek":"Линтер блокирует с идентификатором правила. Хороший барьер показывает решение за правилом и ошибку, которую не даёт вернуть.","tag":"Контроль","read":"4 мин","points":["Блокировка без контекста кажется произвольной и провоцирует обход или удаление правила.","Receipt связывает нарушение с путём кода, исходным решением и историческим доказательством.","Проверяемая причина помогает отличить настоящую регрессию от правила, которое уже потеряло актуальность."],"takeaway":"Доверие к контролю рождается из прозрачности. Показывайте не только сбой, но и причину правила и безопасный путь к прохождению."},{"slug":"prevent-and-catch","title":"Предотвратить и поймать: зачем нужны оба слоя","dek":"Инъекция контекста предотвращает нарушения, которым модель готова следовать. Детерминированный барьер ловит остальные. Одного слоя недостаточно.","tag":"Стратегия","read":"5 мин","points":["Раннее предотвращение экономит работу: агент видит причину до правки и сразу выбирает правильный путь.","Но модель может проигнорировать, неверно понять или потерять инструкцию в длинном контексте.","Проверка после изменения даёт объективную страховку и полезный receipt для исправления."],"takeaway":"Используйте память для направления, а барьер — для гарантии. Оба слоя опираются на одно правило, но работают в разные моменты."},{"slug":"ai-code-review-is-not-enough","title":"ИИ-ревью необходимо. Но это не барьер.","dek":"CodeRabbit, Greptile и Qodo помогают ревьюить ИИ-PR в масштабе. Но ИИ-рецензент — вероятностный комментатор, а архитектурный дрейф требует детерминированной проверки.","tag":"Сравнение","read":"5 мин","points":["ИИ-ревью хорошо объясняет, замечает запахи и направляет внимание человека к рискованным местам.","Одно изменение может получить разные комментарии в разных запусках, поэтому комментарий не является надёжным контрактом.","Детерминированные правила графа дополняют ревью стабильным pass/fail для критических границ."],"takeaway":"Оставьте богатое суждение ревью, а ограничения, которые нельзя нарушать, — повторяемому барьеру с одинаковым ответом."},{"slug":"conformance-in-ci-in-5-minutes","title":"Архитектурное соответствие в CI за 5 минут","dek":"Запишите одно ограничение, подключите один барьер и увидьте, как он блокирует ИИ-изменение, нарушающее архитектуру, пропуская всё остальное.","tag":"Практика","read":"4 мин","points":["Начните с узкого ценного правила, например запрета контроллерам напрямую достигать слоя базы данных.","Запустите Hunch локально и проверьте область и receipt до добавления в CI.","Добавьте команду соответствия в workflow, чтобы каждый PR проверялся тем же графом и источником истины."],"takeaway":"Первый успех должен быть малым и измеримым: намеренное нарушение падает, корректное изменение проходит, а команда понимает объяснение."}]},"ar":{"dateLocale":"ar","ui":{"pageTitle":"مدونة Hunch — التوافق المعماري لكود الذكاء الاصطناعي","pageDescription":"ملاحظات وقياسات وحجج حول إبقاء الكود الذي ينشئه الذكاء الاصطناعي داخل معماريتك.","mainNav":"التنقل الرئيسي","language":"اللغة","navHow":"كيف يعمل","navInside":"ما وراء الكواليس","docs":"الوثائق","blog":"المدونة","changelog":"سجل التغييرات","getStarted":"ابدأ الآن","eyebrow":"مدونة Hunch","mastheadTitle":"نُبقي الذكاء الاصطناعي داخل معماريتك.","mastheadIntro":"قياسات وحجج وملاحظات ميدانية عن الأخطاء التي لا يراها المدقق — وعن البوابة الحتمية التي تلتقطها.","pinned":"مميّز","allPosts":"كل المقالات","pinnedLabel":"★ مميّز","readRelease":"اقرأ المقال","read":"قراءة","blogName":"مدونة Hunch","notFound":"المقال غير موجود","notFoundBody":"هذا المقال غير موجود.","backToBlog":"العودة إلى المدونة","older":"→ أقدم","newer":"أحدث ←","ctaTitle":"احمِ معماريتك مع كل تغيير ينشئه الذكاء الاصطناعي.","ctaBody":"قيد واحد، بوابة واحدة، من دون نموذج يصدر الحكم.","keyIdeas":"الأفكار الرئيسية","takeawayHeading":"الخلاصة العملية","footerTag":"© Hunch — التوافق المعماري لكود الذكاء الاصطناعي.","allPostsFooter":"كل المقالات"},"posts":[{"slug":"one-memory-for-the-whole-team","title":"Hunch 1.9: ذاكرة حية واحدة للفريق كله","dek":"ينقل وضع Matrix الذاكرة الهندسية إلى مستودع Git خاص ومخصص يتحكم به الفريق، ويحافظ على كل نسخة وworktree وفحص CLI ومساعد متصل على الرسم الحي نفسه.","tag":"إصدار","read":"5 دقائق","points":["يربط مسؤول واحد مستودع الذاكرة الخاص مرة واحدة، ولا يحتفظ مستودع الشيفرة إلا بمؤشر بلا بيانات اعتماد.","تحدّث عمليات CLI وأدوات MCP الرسم، وتتزامن السجلات تلقائيًا مع دمج حتمي.","تبقى الذاكرة خاصة، وتظل صلاحية الحظر بحاجة إلى إجراء بشري صريح."],"takeaway":"يمنح Matrix الفريق كله تاريخًا هندسيًا واحدًا من دون تسليم التخزين أو الصلاحية إلى Hunch."},{"slug":"python-joins-the-graph","title":"Hunch 1.8.1: الرسم البياني يتعلم Python","dek":"جعل الذكاء الاصطناعي Python اللغة الأكثر شعبية على GitHub، ويمكن للانحراف المعماري أن يختبئ في كود Python الذي يكتبه الذكاء الاصطناعي من دون مترجم يراقبه. يضيف الإصدار 1.8.1 الرموز والاستدعاءات والاستيرادات ونطاق التأثير.","tag":"إصدار","read":"7 دقائق","points":["يربط المحلل الجديد الدوال والفئات والاستيرادات والاستدعاءات بالرسم البياني نفسه المستخدم في فحوص التوافق.","يفصل سجل اللغات بين محرك الرسم البياني وبنية اللغة، لذلك تُضاف اللغة التالية بمهايئ صغير بدلاً من إعادة كتابة النظام.","جاء الإصدار من طلب المجتمع واختُبر على مستودعات Python حقيقية، بما في ذلك تحليل نطاق التأثير."],"takeaway":"لا تفيد الذاكرة الهندسية إلا إذا وصلت إلى الكود الذي يعمل عليه الفريق. والآن تنطبق القواعد والتفسيرات نفسها على قواعد كود Python."},{"slug":"change-gate-private-workflows","title":"Hunch 1.5: ذاكرة لكل تغيير في الكود — قبل إرساله","dek":"تجلب Change Gate الجديدة فحص ما قبل الإرسال الحتمي نفسه إلى CLI وMCP وVS Code. وتُبقي الطبقات الخاصة التفسيرات الحساسة محلياً.","tag":"إصدار","read":"7 دقائق","points":["يعمل فحص التوافق نفسه قبل إرسال التغيير مهما كان الوكيل أو المحرر الذي كتبه.","تأتي القواعد مع الأدلة، فتشرح البوابة القرار الذي تحميه والعطل الذي تمنع عودته.","تسمح private overlays بإبقاء السياق الحساس خارج المستودع العام مع استخدامه في العمل المحلي."],"takeaway":"القيمة ليست تعليقاً إضافياً بعد طلب الدمج، بل بوابة واحدة ثابتة تعمل قبل أن يغادر التغيير بيئة العمل."},{"slug":"skills-are-never-read","title":"ثبّتنا مهارة للوكيل في 20 جلسة. لم تُقرأ مرة واحدة.","dek":"أظهر قياس على أعطال zod حقيقية أن المهارة المكتوبة بعناية لم تغيّر شيئاً لأن النماذج لم تفتحها. وحوّل التسليم الإجباري الأعطال الصعبة من FAIL إلى PASS.","tag":"قياس","read":"9 دقائق","points":["وجود ملف تعليمات في المستودع لا يضمن أن يراه الوكيل عندما يحتاج إليه.","في 20 جلسة لم يقرأ أي نموذج المهارة، فبقيت النتيجة مماثلة تماماً لسيناريو بلا تعليمات.","غيّر تسليم التعليمات عبر hook لا يمكن تجاهله النتائج، ثم التقطت بوابة التوافق خطأً ارتكبه مؤلف الأداة نفسه."],"takeaway":"لا تقس جودة التعليمات فقط؛ قِس وصولها فعلياً، ثم استخدم فحصاً حتمياً للحالات التي يظل النموذج فيها غير ملتزم."},{"slug":"agent-audits-its-own-memory","title":"تركنا الذكاء الاصطناعي يراجع أداة ذاكرته. استخدم 4 أدوات من أصل 19.","dek":"بعد أسبوعين من العمل الحقيقي داخل Hunch راجع الوكيل المواضع التي عاد فيها إلى grep وأسباب ذلك. تحولت النتائج إلى v1.3.0 ورفعت Recall@10 من 90% إلى 100%.","tag":"اختبار ذاتي","read":"6 دقائق","points":["لا تعني قائمة القدرات الطويلة استخداماً جيداً؛ اختار الوكيل مسارات مألوفة قليلة وتجاهل البقية.","قارنت المراجعة بين غرض الأدوات والسلوك الفعلي، خاصة عندما بدا grep أسهل من الذاكرة المدمجة.","أُثبتت التحسينات على golden set محفوظ، وخفّضت إعادة استخدام السياق تكلفة التجميع بنحو مئة مرة."],"takeaway":"قيّم أداة الوكيل من خلال سلوك الوكيل لا قائمة مزاياها. راقب مسارات الاستخدام الفعلية واجعل الطريق إلى الإجابة الصحيحة أقصر."},{"slug":"ai-ignores-your-architecture","title":"الذكاء الاصطناعي يتجاهل قواعد معماريتك — حتى في أحدث النماذج. لقد قسنا ذلك.","dek":"قد يعيد الذكاء الاصطناعي كتابة controller ليتصل بقاعدة البيانات مباشرة بينما تبقى Semgrep وSonarQube وESLint خضراء. اختبرنا ما إذا كان إظهار القاعدة للنموذج يكفي.","tag":"قياس","read":"8 دقائق","points":["لا يكون الخرق دائماً نمطاً محظوراً في سطر واحد، بل خاصية لمسار كامل في رسم الاستدعاءات.","حتى مع وجود القاعدة صراحة في السياق، قد يختار النموذج تغييراً يبدو نظيفاً محلياً لكنه خاطئ معمارياً.","نجحت فحوص البنية والأنماط، بينما كشف الفحص الحتمي لمسار controller→database الخرق."],"takeaway":"تعليم النموذج مفيد لكنه ليس بوابة. مثّل القواعد الحرجة بطريقة يستطيع الرسم البياني فحصها بعد كتابة الكود."},{"slug":"agents-md-is-lying-to-your-agent","title":"ملف AGENTS.md يكذب على وكيلك — ولا شيء يتحقق منه","dek":"اعتمدت المنظومة ذاكرة Markdown مثل AGENTS.md وCLAUDE.md وملفات القواعد. تُحفظ في Git ويمكن مراجعتها، لكنها تتقادم بصمت وتبقى ذات سلطة.","tag":"إصدار","read":"5 دقائق","points":["قد تستمر تعليمة قديمة في الوصول إلى الوكيل بعد تغيّر الكود والمعمارية.","يبدو الملف رسمياً، لذلك يعامل الوكيل المعلومة القديمة كقاعدة فعالة.","يتعامل Hunch 1.1 مع ملفات التعليمات كسطح للانحراف ويقارنها بالبنية والقرارات الحالية."],"takeaway":"تحتاج الذاكرة المكتوبة إلى دورة حياة: مصدر وتاريخ ومالك وفحص توافق. من دون ذلك تتحول الوثائق الجيدة تدريجياً إلى تعليمات ضارة."},{"slug":"the-violation-your-linter-cant-see","title":"الخرق الذي لا يراه المدقق","dek":"تطابق Semgrep وSonarQube وESLint الأنماط، لكن أغلى أخطاء الذكاء الاصطناعي غالباً ما تكون خصائص لرسم الاستدعاءات لا أنماطاً نصية.","tag":"شرح معمّق","read":"6 دقائق","points":["تنجح أدوات الأنماط في إيجاد API محظور أو بنية معروفة، لكنها لا تثبت مساراً يمر عبر عدة دوال.","تتطلب قاعدة مثل «يجب ألا تصل controllers إلى قاعدة البيانات» فهم الرموز والاستدعاءات والتبعيات بين الملفات.","يتيح الرسم الحتمي فحص must-reach وmust-not-reach واتجاه التبعيات بلا رأي من نموذج."],"takeaway":"استخدم المدقق للأنماط التي يجيدها، وأضف فحص الرسم البياني للقواعد المتعلقة بالمسارات والطبقات والحدود المعمارية."},{"slug":"just-put-it-in-the-prompt","title":"«ضعها في الـprompt فحسب» لا يصمد","dek":"يؤثر السياق فعلاً في السلوك، لكن قياسنا أظهر أن نموذجاً متقدماً تجاهل قاعدة معمارية صريحة في 60% من الحالات. السياق ضروري لكنه غير كافٍ.","tag":"حجة","read":"5 دقائق","points":["يرفع السياق الجيد احتمال الاختيار الصحيح ويشرح سبب وجود القاعدة.","لكنه لا يحول النموذج الاحتمالي إلى نظام إنفاذ؛ قد تتراجع التعليمة الواضحة أمام هدف محلي.","فصل القياس بين التسليم والامتثال والإنفاذ، وأظهر أن لكل طبقة وظيفة مختلفة."],"takeaway":"ضع السبب في الـprompt لمنع الأخطاء، ثم افحص النتيجة حتمياً لالتقاط ما لم يُمنع."},{"slug":"architectural-conformance-explained","title":"شرح التوافق المعماري ببساطة","dek":"كيف تتحول جملة «يجب ألا تلمس controllers قاعدة البيانات» إلى فحص حتمي فوق رسم التبعيات، من دون نموذج في دائرة القرار.","tag":"كيف يعمل","read":"6 دقائق","points":["تُترجم النية البشرية أولاً إلى نطاق دقيق: نقاط بداية وهدف محظور واستثناءات صريحة.","يتتبع الرسم البياني مسارات الاستدعاء الفعلية حتى لو مرت الصلة عبر عدة ملفات أو أغلفة.","تتضمن النتيجة receipt يوضح المسار المخالف والقرار وراء القاعدة والعطل الذي تمنع عودته."],"takeaway":"القاعدة الجيدة محددة وقابلة للدحض ومرتبطة بدليل. هكذا تُفرض المعمارية من دون جعل النموذج حكماً على نفسه."},{"slug":"memory-that-travels-with-your-code","title":"ذاكرة تسافر مع الكود","dek":"قد تكون ذاكرة المساعد على الخادم أو تنتهي صلاحيتها أو تبقى على جهاز واحد. البديل هو قيود وقرارات بصيغة JSON محفوظة في Git ومتاحة لكل مساعد.","tag":"معمارية","read":"5 دقائق","points":["تختفي الذاكرة المرتبطة بمزوّد أو جهاز عند تغيير الفريق أو الأداة أو بيئة العمل.","يمكن مراجعة السجلات البسيطة في Git وإصدار نسخ منها ودمجها بجانب الكود الذي تشرحه.","يتيح MCP وتكامل المحررات لعدة مساعدين القراءة من مصدر حقيقة واحد."],"takeaway":"احفظ المعرفة حيث يعرف الفريق إدارتها: بجانب الكود، بتنسيق مفتوح، مع تاريخ، ومن دون ارتباط بمساعد واحد."},{"slug":"never-twice","title":"لن يحدث مرتين: تصحيح يتحول إلى قاعدة مُلزمة","dek":"تقول للذكاء الاصطناعي «لا تستورد lodash هنا أبداً»، ثم تنسى الجلسة التالية. الحل هو تحويل التصحيح إلى قيد دقيق وقابل للنقل.","tag":"التقاط","read":"5 دقائق","points":["التصحيح البشري إشارة قوية: دفع شخص بالفعل تكلفة الفهم وحدد ما يجب ألا يتكرر.","يحفظ Hunch النطاق والسبب والمثال المضاد كقاعدة قابلة للفحص بدلاً من رسالة محادثة مؤقتة.","تعيش القاعدة في Git وتعمل بالطريقة نفسها مع كل مساعد وكل جلسة لاحقة."],"takeaway":"لا تعِد صياغة التصحيح المهم كل مرة. حوّله مرة واحدة إلى ذاكرة لها نطاق وفحص، ودع النظام يتذكر."},{"slug":"the-receipt","title":"الإيصال: إنفاذ يشرح نفسه","dek":"يحظرك المدقق بمعرّف قاعدة. أما البوابة الجيدة فتحظرك مع القرار وراء القاعدة والعطل الذي تمنع فتحه من جديد.","tag":"إنفاذ","read":"4 دقائق","points":["تبدو الكتلة بلا سياق اعتباطية وتدفع المطور إلى تجاوز القاعدة أو حذفها.","يربط receipt الخرق بمسار الكود والقرار الأصلي والدليل التاريخي الداعم.","عندما يمكن فحص السبب يصبح من الممكن التمييز بين تراجع حقيقي وقاعدة لم تعد صحيحة."],"takeaway":"الثقة في الإنفاذ تأتي من الشفافية. اعرض ما فشل وسبب القاعدة والطريق الآمن لاجتيازها."},{"slug":"prevent-and-catch","title":"المنع والالتقاط: لماذا تحتاج إلى الطبقتين","dek":"يمنع حقن السياق الخروقات التي يستجيب لها النموذج، وتلتقط البوابة الحتمية البقية. يبين قياسنا لماذا لا تكفي طبقة واحدة.","tag":"استراتيجية","read":"5 دقائق","points":["يوفر المنع المبكر العمل لأن الوكيل يرى السبب قبل التعديل ويختار المسار الصحيح من البداية.","لكن النموذج قد يتجاهل التعليمة أو يسيء فهمها أو يفقدها داخل سياق طويل.","يوفر الفحص بعد التغيير شبكة أمان موضوعية وreceipt مفيداً للإصلاح."],"takeaway":"استخدم الذاكرة للتوجيه والبوابة للضمان. تعتمد الطبقتان على القاعدة نفسها لكنهما تعملان في لحظتين مختلفتين."},{"slug":"ai-code-review-is-not-enough","title":"مراجعة الكود بالذكاء الاصطناعي ضرورية، لكنها ليست البوابة","dek":"تجعل CodeRabbit وGreptile وQodo طلبات الدمج التي ينشئها الذكاء الاصطناعي قابلة للمراجعة على نطاق واسع. لكن المراجع الاحتمالي لا يعوض فحصاً معمارياً حتمياً.","tag":"مقارنة","read":"5 دقائق","points":["تجيد مراجعة الذكاء الاصطناعي الشرح واكتشاف الروائح وتوجيه انتباه الإنسان إلى المناطق الخطرة.","قد يتلقى التغيير نفسه تعليقات مختلفة بين تشغيل وآخر، لذلك لا يمثل التعليق عقد إنفاذ موثوقاً.","تكمل قواعد الرسم الحتمية المراجعة بإجابة pass/fail ثابتة للحدود الحرجة."],"takeaway":"اترك الحكم الغني للمراجعة، وضع القيود التي لا يجوز كسرها في بوابة قابلة للتكرار تعطي النتيجة نفسها."},{"slug":"conformance-in-ci-in-5-minutes","title":"شغّل التوافق المعماري في CI خلال 5 دقائق","dek":"سجّل قيداً واحداً، وصّل بوابة واحدة، وشاهدها تحظر تغيير الذكاء الاصطناعي الذي يكسر معماريتك وتمرر كل ما لا يكسرها.","tag":"دليل","read":"4 دقائق","points":["ابدأ بقاعدة ضيقة وعالية القيمة، مثل منع controllers من الوصول مباشرة إلى طبقة قاعدة البيانات.","شغّل Hunch محلياً وتحقق من النطاق والـreceipt قبل إضافته إلى CI.","أضف أمر التوافق إلى workflow حتى يُفحص كل طلب دمج بالرسم ومصدر الحقيقة نفسيهما."],"takeaway":"يجب أن يكون النجاح الأول صغيراً وقابلاً للقياس: يفشل خرق مقصود، ويمر تغيير سليم، ويفهم الفريق التفسير."}]},"es":{"dateLocale":"es-ES","ui":{"pageTitle":"Blog de Hunch — conformidad arquitectónica para código de IA","pageDescription":"Notas, benchmarks y argumentos para mantener el código generado por IA dentro de tu arquitectura.","mainNav":"Navegación principal","language":"Idioma","navHow":"Cómo funciona","navInside":"Cómo está hecho","docs":"Documentación","blog":"Blog","changelog":"Cambios","getStarted":"Empezar","eyebrow":"El blog de Hunch","mastheadTitle":"Mantén la IA dentro de tu arquitectura.","mastheadIntro":"Benchmarks, argumentos y notas de campo sobre los errores que tu linter no ve y la barrera determinista que sí los detecta.","pinned":"Destacado","allPosts":"Todos los artículos","pinnedLabel":"★ Destacado","readRelease":"Leer el artículo","read":"Leer","blogName":"Blog de Hunch","notFound":"Artículo no encontrado","notFoundBody":"Ese artículo no existe.","backToBlog":"Volver al blog","older":"← Anterior","newer":"Más reciente →","ctaTitle":"Protege tu arquitectura en cada cambio de IA.","ctaBody":"Una restricción, una barrera, sin un modelo como juez.","keyIdeas":"Ideas principales","takeawayHeading":"Conclusión práctica","footerTag":"© Hunch — conformidad arquitectónica para código de IA.","allPostsFooter":"Todos los artículos"},"posts":[{"slug":"one-memory-for-the-whole-team","title":"Hunch 1.9: una memoria viva para todo el equipo","dek":"Matrix traslada la memoria de ingeniería a un repositorio Git privado y dedicado que controla el equipo, y mantiene cada clon, worktree, comprobación CLI y asistente conectado sobre el mismo grafo vivo.","tag":"Versión","read":"5 min","points":["Una persona responsable conecta una vez el repositorio privado de memoria; el repositorio de código solo guarda un puntero sin credenciales.","El CLI y MCP refrescan el grafo, y las capturas se sincronizan automáticamente con una fusión determinista.","La memoria sigue siendo privada y la autoridad para bloquear todavía exige una acción humana explícita."],"takeaway":"Matrix ofrece a todo el equipo una historia de ingeniería común sin ceder a Hunch el alojamiento ni la autoridad."},{"slug":"python-joins-the-graph","title":"Hunch 1.8.1: el grafo aprende Python","dek":"La IA convirtió Python en el lenguaje más popular de GitHub, y la deriva arquitectónica se oculta especialmente bien en el Python escrito por IA porque no hay un compilador vigilando. v1.8.1 añade símbolos, llamadas, imports y radio de impacto.","tag":"Versión","read":"7 min","points":["El nuevo analizador conecta funciones, clases, imports y llamadas con el mismo grafo usado por las comprobaciones de conformidad.","Un registro de lenguajes separa el motor del grafo de la sintaxis, por lo que el próximo lenguaje requiere un adaptador, no una reescritura.","La versión nació de una petición de la comunidad y se probó en repositorios Python reales, incluido el análisis de impacto."],"takeaway":"La memoria de ingeniería solo sirve si llega al código del equipo. Ahora las mismas reglas y explicaciones también cubren bases de código Python."},{"slug":"change-gate-private-workflows","title":"Hunch 1.5: memoria para cada cambio de código, antes de enviarlo","dek":"El nuevo Change Gate lleva la misma comprobación determinista previa al CLI, MCP y VS Code. Las capas privadas mantienen el razonamiento sensible en local.","tag":"Versión","read":"7 min","points":["La misma comprobación se ejecuta antes de enviar un cambio, sin importar qué agente o editor lo escribió.","Las reglas incluyen pruebas: un bloqueo explica qué decisión protege y qué error evita reabrir.","Los private overlays permiten mantener el contexto sensible fuera del repositorio público y usarlo en el trabajo local."],"takeaway":"El valor no está en otro comentario después del PR, sino en una única barrera coherente justo antes de que el cambio salga de tu entorno."},{"slug":"skills-are-never-read","title":"Instalamos una skill de agente en 20 sesiones. Se leyó cero veces.","dek":"Un benchmark con errores reales de zod mostró que nuestra skill de rigor no tenía efecto porque ningún modelo la abría. Forzar la entrega convirtió fallos difíciles de FAIL a PASS.","tag":"Benchmark","read":"9 min","points":["Tener un archivo de instrucciones en el repositorio no garantiza que el agente lo vea cuando importa.","En 20 sesiones ningún modelo leyó la skill, así que el resultado fue idéntico al escenario sin instrucciones.","Entregarla mediante un hook imposible de ignorar cambió los resultados, y la barrera atrapó después un error de su propio autor."],"takeaway":"No midas solo la calidad de las instrucciones: mide si se entregan. Después comprueba de forma determinista los casos en que el modelo no obedece."},{"slug":"agent-audits-its-own-memory","title":"Dejamos que la IA auditara su herramienta de memoria. Usaba 4 de 19 herramientas.","dek":"Tras dos semanas de trabajo real dentro de Hunch, el agente revisó dónde volvía a grep y por qué. Los hallazgos llegaron a v1.3.0 y elevaron Recall@10 del 90% al 100%.","tag":"Uso interno","read":"6 min","points":["Una lista larga de capacidades no equivale a buen uso: el agente elegía unas pocas rutas conocidas e ignoraba el resto.","La auditoría comparó el propósito de las herramientas con el comportamiento real, sobre todo donde grep parecía más fácil que la memoria integrada.","Los cambios se probaron contra un golden set guardado y reutilizar contexto redujo el coste de recopilación unas cien veces."],"takeaway":"Evalúa una herramienta de agente por el comportamiento del agente, no por su catálogo. Mide las rutas reales y acorta el camino a la respuesta correcta."},{"slug":"ai-ignores-your-architecture","title":"La IA ignora tus reglas de arquitectura, incluso en la frontera. Lo medimos.","dek":"Una IA puede reescribir un controller para consultar directamente la base de datos mientras Semgrep, SonarQube y ESLint siguen en verde. Probamos si mostrarle la regla era suficiente.","tag":"Benchmark","read":"8 min","points":["La infracción no siempre es un patrón prohibido en una línea; puede ser una propiedad de la ruta en el grafo de llamadas.","Aunque la regla esté explícita en el contexto, el modelo puede preferir un cambio localmente limpio pero arquitectónicamente incorrecto.","Los análisis de sintaxis pasaron, mientras la comprobación determinista de la ruta controller→database detectó la infracción."],"takeaway":"Una instrucción ayuda, pero no es una barrera. Representa las reglas críticas de forma que el grafo pueda comprobar el resultado después de escribir el código."},{"slug":"agents-md-is-lying-to-your-agent","title":"Tu AGENTS.md miente a tu agente y nada lo comprueba","dek":"El ecosistema estandarizó la memoria en Markdown: AGENTS.md, CLAUDE.md y archivos de reglas. Está en Git y se puede revisar, pero se pudre en silencio conservando toda su autoridad.","tag":"Versión","read":"5 min","points":["Una instrucción antigua puede seguir llegando al agente después de que cambien el código y la arquitectura.","El archivo parece oficial, así que el agente trata la información obsoleta como una regla activa.","Hunch 1.1 considera los archivos de instrucciones una superficie de deriva y los compara con la estructura y las decisiones actuales."],"takeaway":"La memoria escrita necesita ciclo de vida: fuente, fecha, responsable y comprobación de conformidad. Sin eso, una buena documentación acaba siendo una instrucción dañina."},{"slug":"the-violation-your-linter-cant-see","title":"La infracción que tu linter no puede ver","dek":"Semgrep, SonarQube y ESLint buscan patrones. Los errores de IA más caros suelen ser propiedades del grafo de llamadas, no patrones de texto.","tag":"Análisis","read":"6 min","points":["Las herramientas de patrones encuentran muy bien una API prohibida o una estructura conocida, pero no demuestran una ruta a través de varias funciones.","Una regla como «los controllers no llegan a la base de datos» exige entender símbolos, llamadas y dependencias entre archivos.","Un grafo determinista comprueba must-reach, must-not-reach y dirección de dependencias sin pedir opinión a un modelo."],"takeaway":"Usa el linter para los patrones que domina y añade una comprobación de grafo para rutas, capas y límites arquitectónicos."},{"slug":"just-put-it-in-the-prompt","title":"«Ponlo en el prompt» no aguanta","dek":"El contexto sí cambia el comportamiento, pero nuestro benchmark muestra que incluso un modelo de frontera ignora una regla arquitectónica explícita el 60% de las veces. Es necesario, no suficiente.","tag":"Argumento","read":"5 min","points":["Un buen contexto aumenta la probabilidad de elegir bien y explica por qué existe la regla.","No convierte un modelo probabilístico en un sistema de ejecución: una instrucción clara todavía puede perder frente a un objetivo local.","El benchmark separó entrega, obediencia y control, y mostró que son tres problemas distintos."],"takeaway":"Pon la razón en el prompt para prevenir errores y comprueba después el resultado de forma determinista para atrapar lo que no se evitó."},{"slug":"architectural-conformance-explained","title":"Conformidad arquitectónica, explicada","dek":"Cómo una frase —«los controllers no deben tocar la base de datos»— se convierte en una comprobación determinista del grafo de dependencias, sin un modelo en la decisión.","tag":"Cómo funciona","read":"6 min","points":["La intención humana se traduce primero a un alcance preciso: puntos de partida, destino prohibido y excepciones explícitas.","El grafo sigue las rutas de llamadas reales aunque la conexión atraviese varios archivos o wrappers.","El resultado incluye un receipt: la ruta infractora, la decisión tras la regla y el error que evita reabrir."],"takeaway":"Una buena regla es concreta, refutable y está vinculada a pruebas. Así se controla la arquitectura sin convertir al modelo en juez de sí mismo."},{"slug":"memory-that-travels-with-your-code","title":"Memoria que viaja con tu código","dek":"La memoria de un asistente puede vivir en un servidor, caducar o quedarse en una máquina. La alternativa: restricciones y decisiones como JSON en Git, portables entre asistentes.","tag":"Arquitectura","read":"5 min","points":["La memoria ligada a un proveedor o dispositivo desaparece al cambiar de equipo, herramienta o entorno.","Los registros simples en Git se pueden revisar, versionar y fusionar junto al código que explican.","MCP y las integraciones de editor permiten que varios asistentes lean la misma fuente de verdad."],"takeaway":"Guarda el conocimiento donde el equipo ya sabe gestionarlo: junto al código, en formato abierto, con historial y sin depender de un único asistente."},{"slug":"never-twice","title":"Nunca dos veces: una corrección se convierte en regla aplicada","dek":"Le dices a la IA «nunca importes lodash aquí» y la siguiente sesión lo olvida. La solución es convertir esa corrección en una restricción precisa y portable.","tag":"Captura","read":"5 min","points":["Una corrección humana es una señal fuerte: alguien ya pagó el coste de entender y definió qué no debe repetirse.","Hunch guarda el alcance, la razón y el contraejemplo como una regla comprobable en vez de una frase efímera del chat.","La regla vive en Git y se aplica igual con cualquier asistente y en cualquier sesión futura."],"takeaway":"No reformules una corrección importante cada vez. Conviértela una vez en memoria con alcance y comprobación, y deja que el sistema recuerde."},{"slug":"the-receipt","title":"El recibo: control que se explica","dek":"Un linter bloquea con un identificador de regla. Una buena barrera bloquea con la decisión que sostiene la regla y el error que evita reabrir.","tag":"Control","read":"4 min","points":["Un bloqueo sin contexto parece arbitrario e invita a saltarse o borrar la regla.","El receipt conecta la infracción con la ruta del código, la decisión original y la prueba histórica.","Cuando la razón se puede revisar, es posible distinguir una regresión real de una regla que ya no es válida."],"takeaway":"La confianza en el control nace de la transparencia. Muestra qué falló, por qué existe la regla y qué debe cambiar para pasar con seguridad."},{"slug":"prevent-and-catch","title":"Prevenir y atrapar: por qué necesitas ambas capas","dek":"La inyección de contexto previene las infracciones que el modelo está dispuesto a evitar. La barrera determinista atrapa las demás. Ninguna capa basta por sí sola.","tag":"Estrategia","read":"5 min","points":["Prevenir pronto ahorra trabajo: el agente ve la razón antes de editar y puede elegir bien desde el principio.","Pero el modelo puede ignorar, malinterpretar o perder la instrucción dentro de un contexto largo.","La comprobación posterior ofrece una red de seguridad objetiva y un receipt útil para corregir."],"takeaway":"Usa la memoria para orientar y la barrera para garantizar. Ambas comparten la misma regla, pero actúan en momentos distintos."},{"slug":"ai-code-review-is-not-enough","title":"La revisión de código con IA es necesaria. No es la barrera.","dek":"CodeRabbit, Greptile y Qodo hacen revisables a escala los PR generados por IA. Pero un revisor de IA es un comentarista probabilístico y la deriva arquitectónica exige una comprobación determinista.","tag":"Comparación","read":"5 min","points":["La revisión con IA explica bien, detecta olores y dirige la atención humana a zonas arriesgadas.","El mismo cambio puede recibir comentarios distintos entre ejecuciones, así que un comentario no es un contrato fiable.","Las reglas deterministas del grafo complementan la revisión con un pass/fail estable para los límites críticos."],"takeaway":"Deja el juicio rico a la revisión y las restricciones que nunca deben romperse a una barrera repetible con el mismo resultado."},{"slug":"conformance-in-ci-in-5-minutes","title":"Ejecuta conformidad arquitectónica en CI en 5 minutos","dek":"Registra una restricción, conecta una barrera y observa cómo bloquea el cambio de IA que rompe tu arquitectura y deja pasar todo lo demás.","tag":"Tutorial","read":"4 min","points":["Empieza con una regla estrecha y valiosa, como impedir que los controllers lleguen directamente a la capa de base de datos.","Ejecuta Hunch en local y comprueba el alcance y el receipt antes de añadirlo al CI.","Añade el comando de conformidad al workflow para que cada PR use el mismo grafo y la misma fuente de verdad."],"takeaway":"El primer éxito debe ser pequeño y medible: una infracción intencionada falla, un cambio correcto pasa y el equipo entiende la explicación."}]}};
(function () {
  const escapeHtml = (value) => String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
  window.localizeBlogPosts = function (sourcePosts, locale) {
    const localeData = window.BLOG_I18N?.[locale];
    if (!localeData) return Array.from(sourcePosts);
    const translations = new Map(localeData.posts.map((entry) => [entry.slug, entry]));
    return Array.from(sourcePosts, (source) => {
      const translated = translations.get(source.slug);
      if (!translated) return source;
      const body = '<p class="lead">' + escapeHtml(translated.dek) + '</p>'
        + '<h2>' + escapeHtml(localeData.ui.keyIdeas) + '</h2><ul>'
        + translated.points.map((point) => '<li>' + escapeHtml(point) + '</li>').join("")
        + '</ul><h2>' + escapeHtml(localeData.ui.takeawayHeading) + '</h2><p>'
        + escapeHtml(translated.takeaway) + '</p>';
      return {
        ...source,
        title: translated.title,
        dek: translated.dek,
        tag: translated.tag,
        read: translated.read,
        body,
        cover: source.cover ? { ...source.cover, alt: translated.title } : source.cover,
      };
    });
  };
})();
